-- ============================================
-- 更新任务表中的冗余字段 (设备名、航线名)
-- ============================================
UPDATE sys_uav_task t
JOIN sys_uav_equipment e ON t.equipment_id = e.equipment_id
JOIN sys_uav_route r ON t.route_id = r.route_id
SET t.equipment_name = e.equipment_name,
    t.route_name = r.route_name;

-- ============================================
-- 完成
-- ============================================
SELECT '演示数据重置完成！' AS message;
SELECT '设备' AS tab, COUNT(*) AS cnt FROM sys_uav_equipment
UNION ALL SELECT '航线', COUNT(*) FROM sys_uav_route
UNION ALL SELECT '任务', COUNT(*) FROM sys_uav_task
UNION ALL SELECT '结果', COUNT(*) FROM sys_uav_result;
